private boolean isFunctionDeclaration(Node node){
  return node != null &&
         ((node.getType() == ASSIGN ||
           node.getType() == VAR ||
           node.getType() == CONST ||
           node.getType() == THIS)
           || isFunctionExpression(node)) ;  
}

